# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka import KafkaAdminClient, NewTopic, AdminCreateTopicsError

def main():
    parser = argparse.ArgumentParser(description="Kafka Cluster Administration")
    parser.add_argument("--bootstrap-servers", required=True, help="List of bootstrap servers (comma-separated)")
    parser.add_argument("--topics", nargs="+", help="Topics to create")
    parser.add_argument("--partitions", type=int, help="Number of partitions per topic (default: 1)")
    parser.add_argument("--replication-factor", type=int, default=1, help="Replication factor for topics (default: 1)")

    args = parser.parse_args()

    with KafkaAdminClient(bootstrap_servers=args.bootstrap_servers) as admin_client:
        for topic in args.topics:
            new_topic = NewTopic(
                topic=topic,
                partitions=args.partitions,
                replication_factor=args.replication_factor
            )

            try:
                admin_client.create_topics( [new_topic] )
                print(f"Topic '{topic}' created successfully.")
            except AdminCreateTopicsError as e:
                errors = e.result()
                for error in errors:
                    if error.topic_error.code() == 13:
                        print(f"Topic '{topic}' already exists.")
                    else:
                        print(f"An error occurred while creating topic '{topic}'. Error code: {error.topic_error.code()}")

if __name__ == "__main__":
    main()